[GQL-OP perf_orders_list]
  query {
    orders(first: 10, sort: "createdDate:desc") {
      totalCount
      items { id number status createdDate total { amount currency { code } } }
    }
  }
[GQL-EXEC perf_orders_list]
[GQL-OP perf_orders_nested]
  query {
    orders(first: 3, sort: "createdDate:desc") {
      items {
        id number status
        total { amount } subTotal { amount } taxTotal { amount }
        items { id productId sku quantity price { amount } }
        addresses { id city countryCode line1 }
        inPayments { id gatewayCode sum { amount } }
        shipments { id shipmentMethodCode price { amount } }
      }
    }
  }
[GQL-EXEC perf_orders_nested]

